for (uint256 i = 0; i < activeLen; i++) {
    address pool = _activeValidators[i];
    if (_validators[pool].status == ValidatorStatus.PENDING_INACTIVE) {
        continue;
    }
    stayingActiveCount++;
}

function _calculateStayingVotingPower() internal view returns (uint256) {
    uint256 total = 0;
    uint256 length = _activeValidators.length;
    for (uint256 i = 0; i < length; i++) {
        address pool = _activeValidators[i];
        if (_validators[pool].status == ValidatorStatus.PENDING_INACTIVE) {
            continue;
        }
        total += _getValidatorVotingPower(pool);
    }
    return total;
}

function _syncBondsAndCalculateTotalVotingPower() internal returns (uint256) {
    uint256 total = 0;
    uint256 length = _activeValidators.length;
    for (uint256 i = 0; i < length; i++) {
        address pool = _activeValidators[i];
        uint256 power = _getValidatorVotingPower(pool);
        _validators[pool].bond = power;
        total += power;
    }
    return total;
}

function _isInPendingInactive(
    address pool
) internal view returns (bool) {
    uint256 length = _pendingInactive.length;
    for (uint256 i = 0; i < length; i++) {
        if (_pendingInactive[i] == pool) {
            return true;
        }
    }
    return false;
}
